CREATE OR REPLACE FUNCTION handle_new_user() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ BEGIN INSERT INTO public.student_profiles (id, full_name, email, onboarding_step, account_status, account_enabled) VALUES (NEW.id, COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.email), NEW.email, 'pending_plan', 'pending', false) ON CONFLICT (id) DO NOTHING; RETURN NEW; END; $$;